// ============================================================
// GIRO v2 — Motor de Estoque + Sazonalidade
// ELEVARIA
// ============================================================

const items = $input.all();
const produtos = items.map(i => i.json);
const hoje = new Date();

// --- Helpers ---
function diasDesde(data) {
  if (!data) return 999;
  return Math.floor((hoje - new Date(data)) / 86400000);
}

function coberturaDias(estoque, v30) {
  if (!v30 || v30 === 0) return 999;
  return Math.round(estoque / (v30 / 30));
}

// --- SAZONALIDADE ---
// Compara vendas_30d vs média mensal dos 90 dias
// Detecta se o produto está acelerando (alta temporada) ou desacelerando
function calcTendencia(v30, v90) {
  if (!v90 || v90 === 0) return { trend: 'SEM_DADO', label: 'Sem dado', vel: 0 };
  const mediaM = v90 / 3; // média mensal dos últimos 3 meses
  const ratio = v30 / mediaM;
  const vel = Math.round((ratio - 1) * 100); // % de variação vs média
  if (ratio >= 1.3) return { trend: 'ALTA',   label: `Alta temporada (+${vel}%)`,    vel };
  if (ratio <= 0.7) return { trend: 'BAIXA',  label: `Baixa temporada (${vel}%)`,    vel };
  return              { trend: 'ESTAVEL',label: `Estável (${vel >= 0 ? '+' : ''}${vel}%)`, vel };
}

// --- Processar produtos ---
const processados = produtos.map(p => {
  const estoque    = parseFloat(p.estoque_atual)   || 0;
  const estoqueMin = parseFloat(p.estoque_minimo)  || 0;
  const v30        = parseFloat(p.vendas_30d)       || 0;
  const v90        = parseFloat(p.vendas_90d)       || 0;
  const custo      = parseFloat(p.preco_custo)      || 0;
  const venda      = parseFloat(p.preco_venda)      || 0;
  const margem     = venda > 0 ? ((venda - custo) / venda * 100) : 0;
  const fat30      = v30 * venda;
  const cobertura  = coberturaDias(estoque, v30);
  const diasSemMov = diasDesde(p.ultima_venda);
  const capParado  = diasSemMov > 90 && estoque > 0 ? estoque * custo : 0;
  const tend       = calcTendencia(v30, v90);

  // Status de estoque
  let status = 'normal', alerta = null;
  if      (estoque === 0 && v30 > 0)           { status = 'ruptura';   alerta = `RUPTURA — demanda ativa, estoque zero`; }
  else if (estoque > 0 && estoque < estoqueMin){ status = 'critico';   alerta = `CRÍTICO — ${estoque} un (mín: ${estoqueMin})`; }
  else if (diasSemMov > 90 && estoque > 0)     { status = 'parado';    alerta = `PARADO — ${diasSemMov} dias sem venda`; }
  else if (cobertura > 120)                    { status = 'excesso';   alerta = `EXCESSO — ${cobertura} dias de cobertura`; }
  else if (cobertura < 15 && v30 > 0)          { status = 'reposicao'; alerta = `REPOR — apenas ${cobertura} dias restantes`; }

  return {
    produto: p.produto,
    sku: p.sku || '-',
    estoque, estoqueMin, v30, v90, custo, venda,
    margem: margem.toFixed(1),
    fat30: fat30.toFixed(2),
    cobertura,
    diasSemMov,
    capParado: capParado.toFixed(2),
    status,
    alerta,
    tendencia: tend
  };
});

// --- Curva ABC ---
const totalFat = processados.reduce((s,p) => s + parseFloat(p.fat30), 0);
const sortedFat = [...processados].sort((a,b) => parseFloat(b.fat30) - parseFloat(a.fat30));
let acum = 0;
sortedFat.forEach(p => {
  acum += parseFloat(p.fat30);
  p.curvaABC = totalFat > 0 ? (acum/totalFat <= 0.7 ? 'A' : acum/totalFat <= 0.9 ? 'B' : 'C') : 'C';
});
processados.forEach(p => {
  const enc = sortedFat.find(x => x.sku === p.sku && x.produto === p.produto);
  if (enc) p.curvaABC = enc.curvaABC;
});

// --- Risco sazonal ---
// Produto Curva A + acelerando + estoque < 2x mínimo = risco máximo
processados.forEach(p => {
  p.riscoSazonal = p.curvaABC === 'A' && p.tendencia.trend === 'ALTA' && p.estoque < p.estoqueMin * 2;
});

// --- Filtros ---
const rupturas    = processados.filter(p => p.status === 'ruptura');
const criticos    = processados.filter(p => p.status === 'critico');
const parados     = processados.filter(p => p.status === 'parado');
const excessos    = processados.filter(p => p.status === 'excesso');
const reposicoes  = processados.filter(p => p.status === 'reposicao');
const curvaA      = processados.filter(p => p.curvaABC === 'A');
const altaTemp    = processados.filter(p => p.tendencia.trend === 'ALTA');
const baixaTemp   = processados.filter(p => p.tendencia.trend === 'BAIXA');
const riscoSazon  = processados.filter(p => p.riscoSazonal);

const totalCap    = processados.reduce((s,p) => s + parseFloat(p.capParado), 0);
const totalFat30  = processados.reduce((s,p) => s + parseFloat(p.fat30), 0);

const resumoEstoque = {
  dataAnalise: hoje.toLocaleDateString('pt-BR'),
  totalProdutos: processados.length,
  totalFaturamento30d: totalFat30.toFixed(2),
  totalCapParado: totalCap.toFixed(2),
  qtdRupturas: rupturas.length,
  qtdCriticos: criticos.length,
  qtdParados: parados.length,
  qtdExcessos: excessos.length,
  qtdReposicoes: reposicoes.length,
  qtdCurvaA: curvaA.length,
  qtdAltaTemp: altaTemp.length,
  qtdBaixaTemp: baixaTemp.length,
  qtdRiscoSazonal: riscoSazon.length,
  produtosRuptura: rupturas.map(p => p.produto),
  produtosCriticos: criticos.slice(0,5).map(p => `${p.produto} (${p.estoque} un)`),
  produtosParados: parados.slice(0,5).map(p => p.produto),
  produtosAltaTemp: altaTemp.slice(0,5).map(p => `${p.produto} (${p.tendencia.label})`),
  produtosRiscoSazonal: riscoSazon.map(p => `${p.produto} — Curva A, ${p.tendencia.label}, ${p.estoque} un`),
  topCurvaA: curvaA.slice(0,5).map(p => p.produto)
};

return [{
  json: {
    resumoEstoque,
    produtos: processados,
    alertas: processados.filter(p => p.alerta).map(p => ({ produto: p.produto, alerta: p.alerta, status: p.status, riscoSazonal: p.riscoSazonal }))
  }
}];

// ============================================================
// GIRO v2 — Motor RFM de Clientes
// ELEVARIA
// ============================================================
// Este nó recebe dados de clientes (input) e recupera
// o resumo de estoque do nó anterior para consolidar tudo.

const clienteItems = $input.all();
const clientes = clienteItems.map(i => i.json);
const hoje = new Date();

// Recuperar análise de estoque do nó anterior na cadeia
const estoqueData = $('Calcular KPIs + Sazonalidade').first().json;

// --- Normalização para scores 1-5 ---
const maxCompras = Math.max(...clientes.map(c => parseFloat(c.total_compras) || 0), 1);
const maxValor   = Math.max(...clientes.map(c => parseFloat(c.valor_total)   || 0), 1);

// --- Calcular RFM para cada cliente ---
const cliProcessados = clientes.map(c => {
  const dias    = c.ultima_compra ? Math.floor((hoje - new Date(c.ultima_compra)) / 86400000) : 999;
  const compras = parseFloat(c.total_compras) || 0;
  const valor   = parseFloat(c.valor_total)   || 0;

  // Recência (R) — quanto menor o tempo, maior o score
  const R = dias <= 14 ? 5 : dias <= 30 ? 4 : dias <= 60 ? 3 : dias <= 90 ? 2 : 1;
  // Frequência (F) — normalizado pelo máximo do dataset
  const F = Math.max(1, Math.ceil((compras / maxCompras) * 5));
  // Valor Monetário (M) — normalizado pelo máximo do dataset
  const M = Math.max(1, Math.ceil((valor   / maxValor)   * 5));

  // Pesos: Recência 40%, Frequência 30%, Monetário 30%
  const score = R * 0.4 + F * 0.3 + M * 0.3;

  // Classificação
  let classe, emRisco = false;
  if      (R >= 4 && F >= 4 && M >= 4) { classe = 'Champion'; }
  else if (F >= 4 && R >= 3)           { classe = 'Leal'; }
  else if (R >= 4 && F <= 2)           { classe = 'Novo Potencial'; }
  else if (R <= 2 && F >= 3)           { classe = 'Perdido';  emRisco = true; }
  else if (R === 3 && F >= 2)          { classe = 'Em Risco'; emRisco = true; }
  else if (R <= 2 && F <= 2)           { classe = 'Dormente'; }
  else                                  { classe = 'Potencial'; }

  return {
    nome: c.nome || c.cliente_id || 'Cliente sem nome',
    ultimaCompra: c.ultima_compra,
    diasSemComprar: dias,
    totalCompras: compras,
    valorTotal: valor,
    R, F, M, score: score.toFixed(2),
    classe,
    emRisco
  };
});

// --- Resumo RFM ---
const champions   = cliProcessados.filter(c => c.classe === 'Champion');
const leais       = cliProcessados.filter(c => c.classe === 'Leal');
const emRisco     = cliProcessados.filter(c => c.emRisco);
const perdidos    = cliProcessados.filter(c => c.classe === 'Perdido' || c.classe === 'Dormente');
const novos       = cliProcessados.filter(c => c.classe === 'Novo Potencial');
const valorEmRisco= emRisco.reduce((s,c) => s + c.valorTotal, 0);

const resumoRFM = {
  totalClientes: cliProcessados.length,
  qtdChampions: champions.length,
  qtdLeais: leais.length,
  qtdEmRisco: emRisco.length,
  qtdPerdidos: perdidos.length,
  qtdNovos: novos.length,
  valorEmRisco: valorEmRisco.toFixed(2),
  nomeChampions: champions.map(c => c.nome),
  nomeEmRisco: emRisco.map(c => `${c.nome} (${c.diasSemComprar} dias sem comprar)`),
  nomePerdidos: perdidos.slice(0,5).map(c => c.nome),
  nomeNovos: novos.map(c => c.nome)
};

// --- Consolidar tudo para o próximo nó ---
return [{
  json: {
    resumoEstoque: estoqueData.resumoEstoque,
    alertasEstoque: estoqueData.alertas,
    resumoRFM,
    clientes: cliProcessados
  }
}];

